importScripts('./assets/js/data/swconf.js');

const purgeCache = swconf.purge;
const interceptor = swconf.interceptor || { paths: [], urlPrefixes: [] };
const networkFirstPaths = new Set([
  '/assets/css/jekyll-theme-chirpy.css',
  '/assets/js/data/mathjax.js',
]);

const isInterceptedPath = (url) => {
  for (const prefix of interceptor.urlPrefixes || []) {
    if (url.href.startsWith(prefix)) {
      return true;
    }
  }

  for (const path of interceptor.paths || []) {
    if (url.pathname.startsWith(path)) {
      return true;
    }
  }

  return false;
};

const shouldCache = (request) => {
  if (purgeCache || request.method !== 'GET') {
    return false;
  }

  const url = new URL(request.url);
  return url.protocol.startsWith('http') && !isInterceptedPath(url);
};

const cacheResponse = (request, response) => {
  if (!shouldCache(request)) {
    return;
  }

  const responseCopy = response.clone();
  caches
    .open(swconf.cacheName)
    .then((cache) => cache.put(request, responseCopy))
    .catch(() => undefined);
};

const fetchFromNetworkFirst = (request) =>
  fetch(request)
    .then((response) => {
      cacheResponse(request, response);
      return response;
    })
    .catch(() =>
      caches.match(request).then((cachedResponse) => {
        if (cachedResponse) {
          return cachedResponse;
        }

        return Promise.reject(new Error(`No cached response for ${request.url}`));
      })
    );

const fetchFromCacheFirst = (request) =>
  caches.match(request).then(
    (cachedResponse) =>
      cachedResponse ||
      fetch(request).then((response) => {
        cacheResponse(request, response);
        return response;
      })
  );

self.addEventListener('install', (event) => {
  self.skipWaiting();

  if (purgeCache) {
    return;
  }

  event.waitUntil(
    caches.open(swconf.cacheName).then((cache) => cache.addAll(swconf.resources))
  );
});

self.addEventListener('activate', (event) => {
  event.waitUntil(
    caches
      .keys()
      .then((cacheNames) =>
        Promise.all(
          cacheNames.map((cacheName) =>
            !purgeCache && cacheName === swconf.cacheName
              ? undefined
              : caches.delete(cacheName)
          )
        )
      )
      .then(() => self.clients.claim())
  );
});

self.addEventListener('message', (event) => {
  if (event.data === 'SKIP_WAITING') {
    self.skipWaiting();
  }
});

self.addEventListener('fetch', (event) => {
  if (event.request.headers.has('range')) {
    return;
  }

  const url = new URL(event.request.url);
  const response = networkFirstPaths.has(url.pathname)
    ? fetchFromNetworkFirst(event.request)
    : fetchFromCacheFirst(event.request);

  event.respondWith(response);
});
